// Parse and structure the order data
const body = $input.first().json.body || {};

// Basic Validation
const errors = [];
if (!body.shopDomain) errors.push('Missing shopDomain');
if (!body.items || !body.items.length) errors.push('Missing items');
if (!body.name) errors.push('Missing name');
if (!body.phone) errors.push('Missing phone');

if (errors.length > 0) {
  return [{ json: { valid: false, errors, body } }];
}

return [{
  json: {
    valid: true,
    shopDomain: body.shopDomain,
    orderData: body
  }
}];

// Find matching store credential
const stores = $input.all().map(i => i.json);
const requestData = $('Validate Input').first().json;
const shopDomain = requestData.shopDomain;

const store = stores.find(s => s.shopDomain === shopDomain || s.subdomain === shopDomain.replace('.myshopify.com', ''));

if (!store) {
  return [{ json: { found: false, error: 'Store not found in database' } }];
}

if (!store.accessToken) {
   return [{ json: { found: false, error: 'Store credentials missing (accessToken)' } }];
}

return [{ json: { found: true, store, orderData: requestData.orderData } }];

// Build Shopify Order GraphQL Mutation
const { store, orderData } = $input.first().json;

// 1. Line Items
let lineItems = [];
if (orderData.variantId) {
  let vid = String(orderData.variantId);
  if (!vid.startsWith('gid://')) vid = `gid://shopify/ProductVariant/${vid}`;
  lineItems.push({ variantId: vid, quantity: orderData.quantity || 1 });
} else {
  // Custom items
  lineItems = (orderData.items || []).map(item => ({
     title: item.title || orderData.productTitle || 'Product',
     quantity: item.quantity || 1,
     originalUnitPrice: String(item.price || orderData.totalPrice || 0)
  }));
}

// 2. Customer & Address
const rawName = (orderData.name || '').trim();
const spaceIndex = rawName.indexOf(' ');
let firstName = spaceIndex > -1 ? rawName.substring(0, spaceIndex) : rawName;
let lastName = spaceIndex > -1 ? rawName.substring(spaceIndex + 1) : '.';
if (!firstName) firstName = 'Customer';

// Ensure Phone is formatted (E.164 for Algeria)
let phone = (orderData.phone || '').replace(/\s+/g, '');
if (phone.startsWith('0')) phone = '+213' + phone.substring(1);
if (phone.length === 9 && !phone.startsWith('+')) phone = '+213' + phone;

const address = {
  firstName,
  lastName,
  phone,
  address1: orderData.address || 'No Address Provided',
  city: orderData.commune || orderData.city || '',
  province: orderData.wilaya || orderData.province || '',
  countryCode: 'DZ'
};

// 3. Custom Attributes (Note Attributes)
const customAttributes = [];
const addAttr = (key, val) => {
  if (val !== undefined && val !== null && val !== '') {
    customAttributes.push({ key, value: String(val) });
  }
};

addAttr('Form ID', orderData.formId);
addAttr('Offer ID', orderData.offerId);
addAttr('Shipping Type', orderData.shippingType);
addAttr('Promo Code', orderData.promo);

const cleanWilaya = (orderData.wilaya || '').replace(/^\d+\s*-\s*/, '');
addAttr('Wilaya Name', cleanWilaya);
addAttr('Wilaya ID', orderData.wilayaId);
addAttr('Commune Name', orderData.commune);
addAttr('Commune ID', orderData.communeId);

// 4. Tags
const tags = ['FinalForm', 'COD'];
if (orderData.shippingType) tags.push(`${orderData.shippingType}-delivery`);
if (orderData.promo) tags.push('PROMO');
if (orderData.tags && Array.isArray(orderData.tags)) tags.push(...orderData.tags);

// 5. Shipping Line
const shippingLines = [];
if (orderData.shippingPrice && Number(orderData.shippingPrice) > 0) {
  shippingLines.push({
    title: orderData.shippingType === 'desk' ? 'Stop Desk Delivery' : 'Home Delivery',
    price: String(orderData.shippingPrice)
  });
}

// 6. Applied Discount
let appliedDiscount = null;
if (orderData.promoDiscount && Number(orderData.promoDiscount) > 0) {
  appliedDiscount = {
    description: orderData.promo || 'Discount',
    value: String(orderData.promoDiscount),
    valueType: 'FIXED_AMOUNT',
    title: orderData.promo || 'Promo'
  };
}

// 7. Build Mutation Input
const orderInput = {
  order: {
    lineItems,
    shippingLines,
    shippingAddress: address,
    billingAddress: address,
    email: orderData.email || null,
    phone: phone,
    note: orderData.note || '',
    customAttributes,
    tags,
    financialStatus: 'PENDING'
  },
  options: {
    inventoryBehaviour: 'BYPASS'
  }
};

// Add discount if exists
if (appliedDiscount) {
  orderInput.order.appliedDiscount = appliedDiscount;
}

// Corrected Mutation Signature
const query = `mutation orderCreate($order: OrderCreateOrderInput!, $options: OrderCreateOptionsInput) {
  orderCreate(order: $order, options: $options) {
    order { id name displayFinancialStatus legacyResourceId }
    userErrors { field message }
  }
}`;

return [{ json: { graphqlQuery: query, graphqlVariables: orderInput, store, orderData } }];

// Parse Response
const input = $input.first().json;
const orderData = $('Build Mutation').first().json.orderData;

// Check Network/Auth Errors (top-level)
if (input.errors) {
   return [{ json: { success: false, errorType: 'GRAPHQL_SYSTEM', errors: input.errors.map(e => e.message) } }];
}

// Check User Errors (logic)
const result = input.data?.orderCreate;
if (!result) {
   return [{ json: { success: false, errorType: 'NO_DATA', errors: ['No data returned from Shopify'] } }];
}

if (result.userErrors && result.userErrors.length > 0) {
   return [{ json: { success: false, errorType: 'USER_ERROR', errors: result.userErrors.map(e => `${e.field}: ${e.message}`) } }];
}

// Success
const order = result.order;
return [{
  json: {
    success: true,
    orderId: order.name,
    shopifyId: order.id,
    legacyId: order.legacyResourceId,
    financialStatus: order.displayFinancialStatus,
    message: 'Order created successfully'
  }
}];
